/**
 * Mutation-hardening tests for magic-byte sniffing and dimension parsing.
 *
 * These tests have teeth: each one targets a specific surviving mutant from Stryker and would
 * FAIL if the corresponding byte comparison, bounds check, boundary operator, or arithmetic were
 * altered. They probe every individual magic-byte position, every length-boundary (`>=` vs `>`),
 * every zero-dimension guard, and the exact arithmetic of the big-endian readers — exactly the
 * adversarial, boundary-exact coverage claude.md S3.6 demands. No tautological asserts.
 */
import { describe, expect, it } from 'vitest';
import { parseDimensions, sniffFormat } from './image-dimensions.js';
import { makeJpeg, makePng, makeWebpVp8 } from './image-fixtures.test-helper.js';

/** Build a minimal valid VP8L WebP header encoding the given dimensions. */
function makeWebpVp8l(width: number, height: number): Uint8Array {
  const buf = new Uint8Array(25);
  buf.set([0x52, 0x49, 0x46, 0x46], 0);
  buf.set([0x57, 0x45, 0x42, 0x50], 8);
  buf.set([0x56, 0x50, 0x38, 0x4c], 12); // "VP8L"
  buf[20] = 0x2f;
  const packed = (width - 1) | ((height - 1) << 14);
  buf[21] = packed & 0xff;
  buf[22] = (packed >> 8) & 0xff;
  buf[23] = (packed >> 16) & 0xff;
  buf[24] = (packed >> 24) & 0xff;
  return buf;
}

/** Build a minimal valid VP8X WebP header encoding the given dimensions. */
function makeWebpVp8x(width: number, height: number): Uint8Array {
  const buf = new Uint8Array(30);
  buf.set([0x52, 0x49, 0x46, 0x46], 0);
  buf.set([0x57, 0x45, 0x42, 0x50], 8);
  buf.set([0x56, 0x50, 0x38, 0x58], 12); // "VP8X"
  const wm1 = width - 1, hm1 = height - 1;
  buf[24] = wm1 & 0xff;
  buf[25] = (wm1 >> 8) & 0xff;
  buf[26] = (wm1 >> 16) & 0xff;
  buf[27] = hm1 & 0xff;
  buf[28] = (hm1 >> 8) & 0xff;
  buf[29] = (hm1 >> 16) & 0xff;
  return buf;
}

describe('sniffFormat — every magic byte is load-bearing', () => {
  // Kills each `buf[i] === 0xNN -> true` and the `&&`->`||` logical mutants: flipping ANY single
  // signature byte must make the format unrecognised. If a comparison were mutated to a constant
  // true or its operator weakened, one of these corrupted buffers would still be accepted.
  const PNG_SIG_INDICES = [0, 1, 2, 3, 4, 5, 6, 7];
  it.each(PNG_SIG_INDICES)('rejects a PNG with signature byte %i corrupted', (i) => {
    const png = makePng(8, 8);
    png[i] = png[i]! ^ 0xff; // flip to a definitely-wrong value
    expect(sniffFormat(png)).toBeNull();
  });

  const JPEG_SIG_INDICES = [0, 1, 2];
  it.each(JPEG_SIG_INDICES)('rejects a JPEG with signature byte %i corrupted', (i) => {
    const jpg = makeJpeg(8, 8);
    jpg[i] = jpg[i]! ^ 0xff;
    expect(sniffFormat(jpg)).toBeNull();
  });

  // WebP signature lives at indices 0..3 ("RIFF") and 8..11 ("WEBP"); bytes 4..7 are the size.
  const WEBP_SIG_INDICES = [0, 1, 2, 3, 8, 9, 10, 11];
  it.each(WEBP_SIG_INDICES)('rejects a WebP with signature byte %i corrupted', (i) => {
    const webp = makeWebpVp8(8, 8);
    webp[i] = webp[i]! ^ 0xff;
    expect(sniffFormat(webp)).toBeNull();
  });
});

describe('sniffFormat — length boundary is exact (kills >= -> > and EqualityOperator)', () => {
  it('accepts a PNG signature at exactly the 8-byte minimum', () => {
    // A buffer of EXACTLY 8 bytes must still sniff as PNG. `buf.length >= 8` mutated to `> 8`
    // would reject this; mutated to a constant would accept a shorter one (next test).
    const sig = new Uint8Array([0x89, 0x50, 0x4e, 0x47, 0x0d, 0x0a, 0x1a, 0x0a]);
    expect(sniffFormat(sig)).toBe('image/png');
  });

  it('rejects a 7-byte PNG signature (one below the minimum)', () => {
    const short = new Uint8Array([0x89, 0x50, 0x4e, 0x47, 0x0d, 0x0a, 0x1a]);
    expect(sniffFormat(short)).toBeNull();
  });

  it('accepts a JPEG signature at exactly 3 bytes and rejects at 2', () => {
    expect(sniffFormat(new Uint8Array([0xff, 0xd8, 0xff]))).toBe('image/jpeg');
    expect(sniffFormat(new Uint8Array([0xff, 0xd8]))).toBeNull();
  });

  it('accepts a WebP signature at exactly 12 bytes and rejects at 11', () => {
    const exact = new Uint8Array(12);
    exact.set([0x52, 0x49, 0x46, 0x46], 0);
    exact.set([0x57, 0x45, 0x42, 0x50], 8);
    expect(sniffFormat(exact)).toBe('image/webp');
    expect(sniffFormat(exact.slice(0, 11))).toBeNull();
  });
});

describe('PNG dimension parsing — exact arithmetic and bounds (kills readU32BE mutants)', () => {
  it('decodes a width above 0xFFFFFF so the *0x1000000 term is required', () => {
    // width 0x01020304 exercises all four bytes; if `* 0x1000000` became `+` or `/`, or the
    // `<< 16` term flipped sign, the recovered width would differ from this exact value.
    const png = makePng(0x01020304, 7);
    expect(parseDimensions('image/png', png)).toEqual({ width: 0x01020304, height: 7 });
  });

  it('rejects a PNG truncated to exactly 23 bytes (one below the 24-byte minimum)', () => {
    const png = makePng(10, 10).slice(0, 23);
    expect(parseDimensions('image/png', png)).toBeNull();
  });

  it('rejects each individual IHDR tag byte being corrupted', () => {
    for (const i of [12, 13, 14, 15]) {
      const png = makePng(10, 10);
      png[i] = png[i]! ^ 0xff;
      expect(parseDimensions('image/png', png)).toBeNull();
    }
  });

  it('rejects a zero width but accepts width 1 (boundary of the === 0 guard)', () => {
    expect(parseDimensions('image/png', makePng(0, 5))).toBeNull();
    expect(parseDimensions('image/png', makePng(1, 5))).toEqual({ width: 1, height: 5 });
  });

  it('rejects a zero height but accepts height 1', () => {
    expect(parseDimensions('image/png', makePng(5, 0))).toBeNull();
    expect(parseDimensions('image/png', makePng(5, 1))).toEqual({ width: 5, height: 1 });
  });
});

describe('JPEG dimension parsing — marker walk boundaries', () => {
  it('rejects when the first marker byte is not 0xFF', () => {
    const jpg = makeJpeg(10, 10);
    jpg[2] = 0xfe; // segment no longer starts with FF
    expect(parseDimensions('image/jpeg', jpg)).toBeNull();
  });

  it('rejects a JPEG whose declared segment length is exactly 1 (< 2 guard)', () => {
    const jpg = makeJpeg(10, 10);
    jpg[4] = 0x00;
    jpg[5] = 0x01; // segLen === 1 -> below the minimum of 2
    expect(parseDimensions('image/jpeg', jpg)).toBeNull();
  });

  it('treats a marker just past the RST range (0xD8) as standalone, not a length segment', () => {
    // 0xD8/0xD9 and 0xD0..0xD7 are standalone. A value of 0xC0 (SOF) is NOT standalone. This
    // pins the boundary of the `marker >= 0xd0 && marker <= 0xd7` range and the `=== 0xd8` arm.
    const buf = new Uint8Array(22);
    buf.set([0xff, 0xd8], 0); // SOI (standalone)
    buf.set([0xff, 0xd7], 2); // RST7 — top of the standalone range
    buf.set([0xff, 0xc0], 4); // SOF0
    const dv = new DataView(buf.buffer);
    dv.setUint16(6, 0x0011, false);
    buf[8] = 8;
    dv.setUint16(9, 50, false); // height
    dv.setUint16(11, 60, false); // width
    expect(parseDimensions('image/jpeg', buf)).toEqual({ width: 60, height: 50 });
  });

  it('rejects a SOF frame whose width is zero', () => {
    const jpg = makeJpeg(0, 10);
    expect(parseDimensions('image/jpeg', jpg)).toBeNull();
  });

  it('rejects a SOF frame whose height is zero', () => {
    const jpg = makeJpeg(10, 0);
    expect(parseDimensions('image/jpeg', jpg)).toBeNull();
  });
});

describe('WebP sub-format parsing — boundaries and fourcc bytes', () => {
  it('rejects a WebP shorter than the 16-byte fourcc minimum', () => {
    const webp = makeWebpVp8(10, 10).slice(0, 15);
    expect(parseDimensions('image/webp', webp)).toBeNull();
  });

  it('rejects a VP8 whose key-frame header is truncated to 29 bytes (< 30 guard)', () => {
    const webp = makeWebpVp8(10, 10).slice(0, 29);
    expect(parseDimensions('image/webp', webp)).toBeNull();
  });

  it('rejects each corrupted "VP8 " fourcc byte', () => {
    for (const i of [12, 13, 14, 15]) {
      const webp = makeWebpVp8(10, 10);
      webp[i] = webp[i]! ^ 0xff;
      expect(parseDimensions('image/webp', webp)).toBeNull();
    }
  });

  it('rejects a VP8 with zero width or zero height', () => {
    expect(parseDimensions('image/webp', makeWebpVp8(0, 10))).toBeNull();
    expect(parseDimensions('image/webp', makeWebpVp8(10, 0))).toBeNull();
  });

  it('parses VP8L and rejects when its 0x2f signature byte is wrong', () => {
    expect(parseDimensions('image/webp', makeWebpVp8l(300, 200))).toEqual({
      width: 300,
      height: 200,
    });
    const bad = makeWebpVp8l(300, 200);
    bad[20] = 0x00;
    expect(parseDimensions('image/webp', bad)).toBeNull();
  });

  it('rejects a VP8L truncated to 24 bytes (one below the 25-byte minimum)', () => {
    const webp = makeWebpVp8l(300, 200).slice(0, 24);
    expect(parseDimensions('image/webp', webp)).toBeNull();
  });

  it('parses VP8X and recovers the +1 canvas size exactly', () => {
    // width 0x010203 + 1 forces all three little-endian bytes plus the +1 to be exact.
    const w = 0x010203, h = 0x040506;
    expect(parseDimensions('image/webp', makeWebpVp8x(w, h))).toEqual({ width: w, height: h });
  });

  it('rejects each corrupted "VP8X" fourcc byte (15th byte distinguishes X from L)', () => {
    const webp = makeWebpVp8x(100, 100);
    webp[15] = webp[15]! ^ 0xff; // no longer 'X'
    expect(parseDimensions('image/webp', webp)).toBeNull();
  });
});

src/rate-limit.mutation.test.ts.source:
/**
 * Mutation-hardening tests for the sliding-window rate limiter.
 *
 * The existing suite proves allow/deny counts; these pin the EXACT `retryAfterMs` arithmetic and
 * the fail-closed sizing boundary so that mutating `> -> >=`, `Math.max -> Math.min`,
 * `oldest + WINDOW_MS - now` operators, or `<= 0 -> < 0` changes an asserted value and the test
 * fails. Boundary-exact, non-tautological — claude.md S3.6 teeth.
 */
import { describe, expect, it } from 'vitest';
import { RateLimiter, type Clock } from './rate-limit.js';

class FakeClock implements Clock {
  constructor(private t = 0) {}
  now(): number {
    return this.t;
  }
  advance(ms: number): void {
    this.t += ms;
  }
}

const input = (perShopper: number, perTenant: number) =>
  ({
    tenantId: 't1',
    shopperId: 's1',
    perShopperPerMinute: perShopper,
    perTenantPerMinute: perTenant,
  }) as const;

describe('fail-closed sizing returns the full-window retry (kills <= 0 -> < 0)', () => {
  it('a zero per-shopper cap denies with retryAfterMs exactly WINDOW_MS', () => {
    // The fail-closed branch returns retryAfterMs = 60000. If `<= 0` were mutated to `< 0`, the
    // zero cap would fall through to the normal path and compute a DIFFERENT retry value (or 1),
    // so this exact-equality assertion fails the mutant.
    const rl = new RateLimiter(new FakeClock());
    const res = rl.check(input(0, 100));
    expect(res.allowed).toBe(false);
    expect(res.retryAfterMs).toBe(60_000);
  });

  it('a zero per-tenant cap denies with retryAfterMs exactly WINDOW_MS', () => {
    const rl = new RateLimiter(new FakeClock());
    const res = rl.check(input(100, 0));
    expect(res.allowed).toBe(false);
    expect(res.retryAfterMs).toBe(60_000);
  });
});

describe('retryAfterMs is the exact time until the oldest hit leaves the window', () => {
  it('after filling the shopper bucket at t=0, the N+1th denial waits the full window', () => {
    // Oldest in-window hit is at t=0; window is 60000. At now=0 the slot frees at 0+60000-0.
    const clock = new FakeClock();
    const rl = new RateLimiter(clock);
    expect(rl.check(input(1, 100)).allowed).toBe(true); // hit at t=0
    const denied = rl.check(input(1, 100)); // still t=0
    expect(denied.allowed).toBe(false);
    expect(denied.retryAfterMs).toBe(60_000); // exact: oldest(0) + 60000 - now(0)
  });

  it('the retry shrinks by exactly the elapsed time (kills the +/- arithmetic mutant)', () => {
    // Hit at t=0, then probe at t=25000: oldest(0) + 60000 - 25000 = 35000 exactly. A mutated
    // `oldest + WINDOW_MS + now` or `oldest - WINDOW_MS` produces a different number.
    const clock = new FakeClock();
    const rl = new RateLimiter(clock);
    expect(rl.check(input(1, 100)).allowed).toBe(true); // t=0
    clock.advance(25_000);
    const denied = rl.check(input(1, 100));
    expect(denied.allowed).toBe(false);
    expect(denied.retryAfterMs).toBe(35_000);
  });

  it('uses the OLDEST in-window hit, not the newest (kills Math.min/Math.max swap)', () => {
    // Two hits at t=0 and t=10000 with shopper cap 2. Deny at t=10000: the limiting wait is from
    // the OLDEST hit (0): 0 + 60000 - 10000 = 50000. If computeRetryAfterMs used the newest hit
    // it would yield 10000 + 60000 - 10000 = 60000, failing this assertion.
    const clock = new FakeClock();
    const rl = new RateLimiter(clock);
    expect(rl.check(input(2, 100)).allowed).toBe(true); // t=0
    clock.advance(10_000);
    expect(rl.check(input(2, 100)).allowed).toBe(true); // t=10000
    const denied = rl.check(input(2, 100)); // still t=10000, bucket full
    expect(denied.allowed).toBe(false);
    expect(denied.retryAfterMs).toBe(50_000);
  });

  it('takes the MAX wait across the two binding buckets (kills wait > retry boundary)', () => {
    // Both shopper and tenant caps are 1. Shopper hit at t=0, tenant also has a hit at t=0 from a
    // different shopper recorded earlier at t=5000. We make the tenant bucket the binding one with
    // an older hit so the loop must keep the larger wait.
    const clock = new FakeClock();
    const rl = new RateLimiter(clock);
    // tenant bucket: shopper sX hits at t=0 (oldest tenant hit)
    expect(
      rl.check({
        tenantId: 't1',
        shopperId: 'sX',
        perShopperPerMinute: 5,
        perTenantPerMinute: 2,
      }).allowed,
    ).toBe(true);
    clock.advance(20_000); // t=20000
    // shopper s1 hits at t=20000 (oldest shopper hit), tenant now has 2 hits, cap reached
    expect(
      rl.check({
        tenantId: 't1',
        shopperId: 's1',
        perShopperPerMinute: 1,
        perTenantPerMinute: 2,
      }).allowed,
    ).toBe(true);
    // Next s1 request: shopper bucket full (oldest 20000) AND tenant full (oldest 0).
    const denied = rl.check({
      tenantId: 't1',
      shopperId: 's1',
      perShopperPerMinute: 1,
      perTenantPerMinute: 2,
    });
    expect(denied.allowed).toBe(false);
    // shopper wait = 20000+60000-20000 = 60000; tenant wait = 0+60000-20000 = 40000. Max = 60000.
    expect(denied.retryAfterMs).toBe(60_000);
  });

  it('a brand-new key allows its first request (kills a non-empty get() default)', () => {
    // An empty bucket must read as length 0. If the store default were a non-empty array, the very
    // first request at cap 1 would already be "full" and denied. (Note: a string-sentinel default
    // is pruned away by the numeric window filter, so that specific mutant is equivalent.)
    const rl = new RateLimiter(new FakeClock());
    expect(rl.check(input(1, 100)).allowed).toBe(true);
  });

  it('computes the exact retry when only the shopper bucket is the binding cap', () => {
    // Shopper cap 1, tenant cap large. Hit at t=0, deny at t=15000: only the shopper bucket is
    // full, so the tenant arg to computeRetryAfterMs is empty. Exact retry = 0+60000-15000.
    const clock = new FakeClock();
    const rl = new RateLimiter(clock);
    expect(rl.check(input(1, 1000)).allowed).toBe(true); // t=0
    clock.advance(15_000);
    const denied = rl.check(input(1, 1000));
    expect(denied.allowed).toBe(false);
    expect(denied.retryAfterMs).toBe(45_000);
  });

  it('never returns a non-positive retry — floored at 1 (kills Math.max -> Math.min)', () => {
    // Probe at the exact instant the oldest hit leaves the window: oldest(0) + 60000 - 60000 = 0.
    // The bucket still counts it as in-window at the >= boundary, so it is denied, and the floor
    // forces retryAfterMs to 1 rather than 0. Math.min(retry,1) would yield 0 here.
    const clock = new FakeClock();
    const rl = new RateLimiter(clock);
    // cap 1; hit at t=0
    expect(rl.check(input(1, 100)).allowed).toBe(true);
    // advance to exactly 59999 so the t=0 hit is still in-window (cutoff = -1) and binding.
    clock.advance(59_999);
    const denied = rl.check(input(1, 100));
    expect(denied.allowed).toBe(false);
    expect(denied.retryAfterMs).toBe(1); // 0 + 60000 - 59999 = 1 exactly
  });
});

src/image-dimensions.test.ts.source:
/**
 * Tests for pure-TS magic-byte sniffing and dimension parsing. Round-trips synthetic headers for
 * each format, rejects truncated/garbled input fail-closed, and asserts sniff distinguishes the
 * three formats from look-alike bytes.
 */
import { describe, expect, it } from 'vitest';
import fc from 'fast-check';
import { parseDimensions, sniffFormat } from './image-dimensions.js';
import { makeJpeg, makePng, makeWebpVp8 } from './image-fixtures.test-helper.js';

describe('sniffFormat', () => {
  it('identifies each real format from its magic bytes', () => {
    expect(sniffFormat(makePng(1, 1))).toBe('image/png');
    expect(sniffFormat(makeJpeg(1, 1))).toBe('image/jpeg');
    expect(sniffFormat(makeWebpVp8(1, 1))).toBe('image/webp');
  });

  it('returns null for unrecognised or too-short buffers', () => {
    expect(sniffFormat(new Uint8Array([0x00, 0x01, 0x02]))).toBeNull();
    expect(sniffFormat(new Uint8Array([0x89, 0x50]))).toBeNull(); // truncated PNG sig
    expect(sniffFormat(new Uint8Array(0))).toBeNull();
  });

  it('does not confuse a RIFF container that is not WEBP', () => {
    const riffWave = new Uint8Array(12);
    riffWave.set([0x52, 0x49, 0x46, 0x46], 0); // "RIFF"
    riffWave.set([0x57, 0x41, 0x56, 0x45], 8); // "WAVE" not "WEBP"
    expect(sniffFormat(riffWave)).toBeNull();
  });
});

describe('parseDimensions round-trip', () => {
  it('recovers exact PNG dimensions', () => {
    expect(parseDimensions('image/png', makePng(640, 480))).toEqual({ width: 640, height: 480 });
  });

  it('recovers exact JPEG dimensions', () => {
    expect(parseDimensions('image/jpeg', makeJpeg(800, 600))).toEqual({ width: 800, height: 600 });
  });

  it('recovers exact WebP (VP8) dimensions', () => {
    expect(parseDimensions('image/webp', makeWebpVp8(1024, 768))).toEqual({
      width: 1024,
      height: 768,
    });
  });

  it('property: PNG width/height survive a round-trip for arbitrary in-range sizes', () => {
    fc.assert(
      fc.property(
        fc.integer({ min: 1, max: 65535 }),
        fc.integer({ min: 1, max: 65535 }),
        (w, h) => {
          const dims = parseDimensions('image/png', makePng(w, h));
          return dims?.width === w && dims.height === h;
        },
      ),
      { numRuns: 200 },
    );
  });
});

describe('parseDimensions fail-closed', () => {
  it('rejects a truncated PNG IHDR', () => {
    const png = makePng(10, 10).slice(0, 18); // cut inside the dimension fields
    expect(parseDimensions('image/png', png)).toBeNull();
  });

  it('rejects a PNG whose first chunk is not IHDR', () => {
    const png = makePng(10, 10);
    png[12] = 0x00; // corrupt "IHDR"
    expect(parseDimensions('image/png', png)).toBeNull();
  });

  it('rejects a zero-dimension PNG', () => {
    expect(parseDimensions('image/png', makePng(0, 10))).toBeNull();
    expect(parseDimensions('image/png', makePng(10, 0))).toBeNull();
  });

  it('rejects a JPEG with no SOF marker', () => {
    const noSof = new Uint8Array([0xff, 0xd8, 0xff, 0xd9]); // SOI then EOI, no frame
    expect(parseDimensions('image/jpeg', noSof)).toBeNull();
  });

  it('rejects a JPEG with a corrupt segment length', () => {
    const jpg = makeJpeg(10, 10);
    jpg[4] = 0x00;
    jpg[5] = 0x00; // length < 2 -> fail closed
    expect(parseDimensions('image/jpeg', jpg)).toBeNull();
  });

  it('skips standalone JPEG markers then finds the SOF', () => {
    // SOI, RST0 (standalone, no length), SOF0 ...
    const buf = new Uint8Array(22);
    buf.set([0xff, 0xd8], 0);
    buf.set([0xff, 0xd0], 2); // RST0 standalone
    buf.set([0xff, 0xc0], 4); // SOF0
    const dv = new DataView(buf.buffer);
    dv.setUint16(6, 0x0011, false);
    buf[8] = 8;
    dv.setUint16(9, 100, false); // height
    dv.setUint16(11, 200, false); // width
    expect(parseDimensions('image/jpeg', buf)).toEqual({ width: 200, height: 100 });
  });

  it('skips a non-SOF segment (APP0) before reaching the SOF frame', () => {
    // SOI | APP0 (len 4, skipped) | SOF0 with dims — exercises the segment-advance path.
    const buf = new Uint8Array(24);
    buf.set([0xff, 0xd8], 0); // SOI
    buf.set([0xff, 0xe0], 2); // APP0
    const dv = new DataView(buf.buffer);
    dv.setUint16(4, 0x0004, false); // APP0 length = 4 (2 length bytes + 2 payload)
    buf.set([0xff, 0xc0], 8); // SOF0 begins after the APP0 segment
    dv.setUint16(10, 0x0011, false);
    buf[12] = 8;
    dv.setUint16(13, 320, false); // height
    dv.setUint16(15, 240, false); // width
    expect(parseDimensions('image/jpeg', buf)).toEqual({ width: 240, height: 320 });
  });

  it('rejects a truncated WebP VP8 header', () => {
    const webp = makeWebpVp8(10, 10).slice(0, 20);
    expect(parseDimensions('image/webp', webp)).toBeNull();
  });

  it('rejects a WebP with an unknown sub-chunk', () => {
    const webp = makeWebpVp8(10, 10);
    webp.set([0x58, 0x58, 0x58, 0x58], 12); // not VP8/VP8L/VP8X
    expect(parseDimensions('image/webp', webp)).toBeNull();
  });
});

describe('WebP VP8L and VP8X sub-formats', () => {
  it('parses a VP8L lossless header', () => {
    // signature 0x2f at 20, then 14-bit (width-1) + 14-bit (height-1) packed LE from byte 21.
    const buf = new Uint8Array(25);
    buf.set([0x52, 0x49, 0x46, 0x46], 0);
    buf.set([0x57, 0x45, 0x42, 0x50], 8);
    buf.set([0x56, 0x50, 0x38, 0x4c], 12); // "VP8L"
    buf[20] = 0x2f;
    const width = 300, height = 200;
    const packed = (width - 1) | ((height - 1) << 14);
    buf[21] = packed & 0xff;
    buf[22] = (packed >> 8) & 0xff;
    buf[23] = (packed >> 16) & 0xff;
    buf[24] = (packed >> 24) & 0xff;
    expect(parseDimensions('image/webp', buf)).toEqual({ width, height });
  });

  it('parses a VP8X extended header', () => {
    const buf = new Uint8Array(30);
    buf.set([0x52, 0x49, 0x46, 0x46], 0);
    buf.set([0x57, 0x45, 0x42, 0x50], 8);
    buf.set([0x56, 0x50, 0x38, 0x58], 12); // "VP8X"
    const width = 500, height = 400;
    const wm1 = width - 1, hm1 = height - 1;
    buf[24] = wm1 & 0xff;
    buf[25] = (wm1 >> 8) & 0xff;
    buf[26] = (wm1 >> 16) & 0xff;
    buf[27] = hm1 & 0xff;
    buf[28] = (hm1 >> 8) & 0xff;
    buf[29] = (hm1 >> 16) & 0xff;
    expect(parseDimensions('image/webp', buf)).toEqual({ width, height });
  });

  it('rejects a VP8L with a missing signature byte', () => {
    const buf = new Uint8Array(25);
    buf.set([0x52, 0x49, 0x46, 0x46], 0);
    buf.set([0x57, 0x45, 0x42, 0x50], 8);
    buf.set([0x56, 0x50, 0x38, 0x4c], 12);
    buf[20] = 0x00; // wrong signature
    expect(parseDimensions('image/webp', buf)).toBeNull();
  });
});

src/image-validation.test.ts.source:
/**
 * Tests for untrusted-image validation. Adversarial: MIME/extension spoofing, byte-size and
 * dimension boundaries (cap vs cap+1), truncated headers, base64 vs raw, and the sanitizer seam.
 */
import { describe, expect, it } from 'vitest';
import type { ImageRef } from '@tryit/contracts';
import {
  DEFAULT_IMAGE_LIMITS,
  PassthroughImageSanitizer,
  validateImageBytes,
  validateImageRef,
  type ImageSanitizer,
  type ImageValidationLimits,
} from './image-validation.js';
import { makeJpeg, makePng, makeWebpVp8 } from './image-fixtures.test-helper.js';
import { type SniffedFormat } from './image-dimensions.js';

const smallLimits: ImageValidationLimits = { maxBytes: 1000, maxWidth: 100, maxHeight: 100 };

describe('valid samples accepted', () => {
  it('accepts a valid PNG/JPEG/WebP and reports the sniffed format + dimensions', () => {
    const png = validateImageBytes(makePng(50, 40), 'image/png', smallLimits);
    expect(png).toMatchObject({ ok: true, format: 'image/png', width: 50, height: 40 });
    const jpg = validateImageBytes(makeJpeg(60, 30), 'image/jpeg', smallLimits);
    expect(jpg).toMatchObject({ ok: true, format: 'image/jpeg', width: 60, height: 30 });
    const webp = validateImageBytes(makeWebpVp8(80, 80), 'image/webp', smallLimits);
    expect(webp).toMatchObject({ ok: true, format: 'image/webp', width: 80, height: 80 });
  });

  it('accepts when no MIME is declared (sniff-only path)', () => {
    expect(validateImageBytes(makePng(10, 10), undefined, smallLimits).ok).toBe(true);
  });
});

describe('MIME / extension spoofing rejected', () => {
  it('rejects PNG-declared bytes that are actually JPEG', () => {
    // Caller claims image/png (the "extension") but the bytes are a JPEG.
    const res = validateImageBytes(makeJpeg(10, 10), 'image/png', smallLimits);
    expect(res).toEqual({ ok: false, reason: 'mime-mismatch' });
  });

  it('rejects JPEG-declared bytes that are actually PNG', () => {
    expect(validateImageBytes(makePng(10, 10), 'image/jpeg', smallLimits)).toEqual({
      ok: false,
      reason: 'mime-mismatch',
    });
  });
});

describe('byte-size boundary', () => {
  it('accepts a payload exactly at maxBytes', () => {
    // Pad a valid PNG up to exactly maxBytes with trailing bytes (header still parses).
    const png = makePng(10, 10);
    const padded = new Uint8Array(smallLimits.maxBytes);
    padded.set(png, 0);
    const res = validateImageBytes(padded, 'image/png', smallLimits);
    expect(res.ok).toBe(true);
  });

  it('rejects a payload one byte over maxBytes (fail-closed before parse)', () => {
    const over = new Uint8Array(smallLimits.maxBytes + 1);
    over.set(makePng(10, 10), 0);
    expect(validateImageBytes(over, 'image/png', smallLimits)).toEqual({
      ok: false,
      reason: 'too-large',
    });
  });
});

describe('dimension boundary (dimension-bomb defence)', () => {
  it('accepts dimensions exactly at the cap', () => {
    const res = validateImageBytes(makePng(100, 100), 'image/png', smallLimits);
    expect(res.ok).toBe(true);
  });

  it('rejects width one over the cap', () => {
    expect(validateImageBytes(makePng(101, 100), 'image/png', smallLimits)).toEqual({
      ok: false,
      reason: 'dimensions-too-large',
    });
  });

  it('rejects height one over the cap', () => {
    expect(validateImageBytes(makePng(100, 101), 'image/png', smallLimits)).toEqual({
      ok: false,
      reason: 'dimensions-too-large',
    });
  });
});

describe('malformed / truncated input', () => {
  it('rejects unrecognised bytes', () => {
    expect(validateImageBytes(new Uint8Array([1, 2, 3, 4]), undefined, smallLimits)).toEqual({
      ok: false,
      reason: 'unrecognised-format',
    });
  });

  it('rejects a truncated PNG header that sniffs but will not parse', () => {
    const png = makePng(10, 10).slice(0, 16); // valid sig, IHDR cut off
    expect(validateImageBytes(png, 'image/png', smallLimits)).toEqual({
      ok: false,
      reason: 'malformed-header',
    });
  });
});

describe('validateImageRef (base64 path)', () => {
  it('accepts a valid base64 PNG whose bytes match the declared mimeType', () => {
    const ref: ImageRef = {
      kind: 'base64',
      mimeType: 'image/png',
      data: Buffer.from(makePng(20, 20)).toString('base64'),
    };
    expect(validateImageRef(ref, smallLimits)).toMatchObject({ ok: true, format: 'image/png' });
  });

  it('rejects a base64 ref whose declared mimeType disagrees with the bytes', () => {
    const ref: ImageRef = {
      kind: 'base64',
      mimeType: 'image/png',
      data: Buffer.from(makeJpeg(20, 20)).toString('base64'),
    };
    expect(validateImageRef(ref, smallLimits)).toEqual({ ok: false, reason: 'mime-mismatch' });
  });

  it('rejects a URL ref at this boundary (no inline bytes to inspect)', () => {
    const ref: ImageRef = { kind: 'url', url: 'https://example.com/a.png' };
    expect(validateImageRef(ref, smallLimits)).toEqual({
      ok: false,
      reason: 'unrecognised-format',
    });
  });

  it('produces the same verdict for base64 and the equivalent raw bytes', () => {
    const raw = makeWebpVp8(64, 64);
    const fromRaw = validateImageBytes(raw, 'image/webp', smallLimits);
    const fromB64 = validateImageRef(
      { kind: 'base64', mimeType: 'image/webp', data: Buffer.from(raw).toString('base64') },
      smallLimits,
    );
    expect(fromB64).toEqual(fromRaw);
  });
});

describe('sanitizer seam', () => {
  it('passes validated bytes through the injected sanitizer', () => {
    const replacement = new Uint8Array([0xaa, 0xbb]);
    const spy: ImageSanitizer = {
      sanitize(_bytes: Uint8Array, _format: SniffedFormat) {
        return replacement; // production decode+re-encode would return clean bytes
      },
    };
    const res = validateImageBytes(makePng(10, 10), 'image/png', smallLimits, spy);
    expect(res.ok).toBe(true);
    if (res.ok) expect(res.bytes).toEqual(replacement);
  });

  it('default passthrough returns the original validated bytes', () => {
    const bytes = makePng(10, 10);
    const res = validateImageBytes(bytes, 'image/png', smallLimits, new PassthroughImageSanitizer());
    expect(res.ok).toBe(true);
    if (res.ok) expect(res.bytes).toEqual(bytes);
  });
});

describe('defaults', () => {
  it('DEFAULT_IMAGE_LIMITS are sane and used when omitted', () => {
    expect(DEFAULT_IMAGE_LIMITS.maxBytes).toBe(8 * 1024 * 1024);
    // A 10x10 PNG passes under default limits with no explicit limits arg.
    expect(validateImageBytes(makePng(10, 10), 'image/png').ok).toBe(true);
  });
});

src/api-key-auth.test.ts.source:
/**
 * Tests for tenant-scoped API-key issue/verify. Adversarial: tamper, expiry boundaries, tenant
 * isolation, scope enforcement, and a property that no non-genuine secret ever verifies.
 */
import { describe, expect, it } from 'vitest';
import fc from 'fast-check';
import {
  createApiKey,
  verifyApiKey,
  type ApiKeyRecord,
} from './api-key-auth.js';

const TENANT = 'tenant-a';

describe('createApiKey', () => {
  it('never stores the plaintext secret in the record', () => {
    const { plaintext, record } = createApiKey({ tenantId: TENANT, scopes: [] });
    expect(record).not.toHaveProperty('plaintext');
    expect(JSON.stringify(record)).not.toContain(plaintext);
    expect(record.hash).not.toEqual(plaintext);
  });

  it('produces a unique salt and hash per call for distinct secrets', () => {
    const a = createApiKey({ tenantId: TENANT, scopes: [] });
    const b = createApiKey({ tenantId: TENANT, scopes: [] });
    expect(a.record.salt).not.toEqual(b.record.salt);
    expect(a.record.hash).not.toEqual(b.record.hash);
    expect(a.keyId).not.toEqual(b.keyId);
  });
});

describe('verifyApiKey round-trip', () => {
  it('verifies a freshly issued key for its own tenant', () => {
    const { plaintext, record } = createApiKey({ tenantId: TENANT, scopes: ['tryon:create'] });
    expect(verifyApiKey(plaintext, record, { tenantId: TENANT })).toEqual({ ok: true });
  });
});

describe('verifyApiKey tamper rejection', () => {
  it('rejects a one-character tamper of the plaintext', () => {
    const { plaintext, record } = createApiKey({ tenantId: TENANT, scopes: [] });
    const first = plaintext[0] === 'a' ? 'b' : 'a';
    const tampered = first + plaintext.slice(1);
    expect(verifyApiKey(tampered, record, { tenantId: TENANT })).toEqual({
      ok: false,
      reason: 'mismatch',
    });
  });

  it('rejects when the stored hash is mutated by one hex char', () => {
    const { plaintext, record } = createApiKey({ tenantId: TENANT, scopes: [] });
    const ch = record.hash[0] === '0' ? '1' : '0';
    const bad: ApiKeyRecord = { ...record, hash: ch + record.hash.slice(1) };
    expect(verifyApiKey(plaintext, bad, { tenantId: TENANT }).ok).toBe(false);
  });

  it('fails closed on a malformed (empty) record', () => {
    const { plaintext, record } = createApiKey({ tenantId: TENANT, scopes: [] });
    expect(verifyApiKey(plaintext, { ...record, salt: '' }, { tenantId: TENANT })).toEqual({
      ok: false,
      reason: 'malformed',
    });
    expect(verifyApiKey(plaintext, { ...record, hash: '' }, { tenantId: TENANT })).toEqual({
      ok: false,
      reason: 'malformed',
    });
    expect(verifyApiKey('', record, { tenantId: TENANT })).toEqual({
      ok: false,
      reason: 'malformed',
    });
  });

  it('fails closed when the stored hash is not valid hex (undecodable)', () => {
    const { plaintext, record } = createApiKey({ tenantId: TENANT, scopes: [] });
    // 'zz' decodes to an empty buffer under hex -> length mismatch -> still denied.
    const bad: ApiKeyRecord = { ...record, hash: 'zz' };
    expect(verifyApiKey(plaintext, bad, { tenantId: TENANT }).ok).toBe(false);
  });
});

describe('verifyApiKey tenant isolation', () => {
  it('denies a valid secret presented for the wrong tenant', () => {
    const { plaintext, record } = createApiKey({ tenantId: TENANT, scopes: [] });
    expect(verifyApiKey(plaintext, record, { tenantId: 'tenant-b' })).toEqual({
      ok: false,
      reason: 'wrong-tenant',
    });
  });
});

describe('verifyApiKey scope enforcement', () => {
  it('allows when all required scopes are granted', () => {
    const { plaintext, record } = createApiKey({
      tenantId: TENANT,
      scopes: ['tryon:create', 'tryon:read'],
    });
    expect(
      verifyApiKey(plaintext, record, {
        tenantId: TENANT,
        requiredScopes: ['tryon:read'],
      }),
    ).toEqual({ ok: true });
  });

  it('denies when a required scope is missing (least privilege)', () => {
    const { plaintext, record } = createApiKey({ tenantId: TENANT, scopes: ['tryon:read'] });
    expect(
      verifyApiKey(plaintext, record, {
        tenantId: TENANT,
        requiredScopes: ['tryon:create'],
      }),
    ).toEqual({ ok: false, reason: 'missing-scope' });
  });
});

describe('verifyApiKey expiry (injected clock)', () => {
  const base = createApiKey({
    tenantId: TENANT,
    scopes: [],
    expiresAt: '2026-01-01T00:00:00.000Z',
  });
  const expMs = Date.parse('2026-01-01T00:00:00.000Z');

  it('allows one millisecond before expiry', () => {
    const now = new Date(expMs - 1);
    expect(verifyApiKey(base.plaintext, base.record, { tenantId: TENANT, now })).toEqual({
      ok: true,
    });
  });

  it('denies exactly at expiry (inclusive cutoff)', () => {
    const now = new Date(expMs);
    expect(verifyApiKey(base.plaintext, base.record, { tenantId: TENANT, now })).toEqual({
      ok: false,
      reason: 'expired',
    });
  });

  it('denies one millisecond after expiry', () => {
    const now = new Date(expMs + 1);
    expect(verifyApiKey(base.plaintext, base.record, { tenantId: TENANT, now }).reason).toBe(
      'expired',
    );
  });

  it('fails closed when expiresAt is unparseable', () => {
    const bad: ApiKeyRecord = { ...base.record, expiresAt: 'not-a-date' };
    expect(verifyApiKey(base.plaintext, bad, { tenantId: TENANT, now: new Date(0) })).toEqual({
      ok: false,
      reason: 'expired',
    });
  });
});

describe('verifyApiKey property: only the genuine secret verifies', () => {
  it('rejects every secret that is not the issued plaintext', () => {
    const { plaintext, record } = createApiKey({ tenantId: TENANT, scopes: [] });
    fc.assert(
      fc.property(fc.string({ minLength: 1, maxLength: 80 }), (candidate) => {
        const result = verifyApiKey(candidate, record, { tenantId: TENANT });
        if (candidate === plaintext) {
          return result.ok === true;
        }
        return result.ok === false;
      }),
      // scrypt is intentionally expensive; 30 adversarial candidates is ample alongside the
      // explicit one-char-tamper and malformed-record tests above.
      { numRuns: 30 },
    );
  });
});

src/image-dimensions-boundaries.mutation.source:
/**
 * Second-round mutation hardening for image-dimensions: kills the survivors that round-tripping
 * could not — whole-branch `condition -> true` mutants in sniffFormat (caught with cross-format
 * buffers that must NOT be accepted), the bounds-check arithmetic in the big-endian/little-endian
 * readers (caught with byte-exact truncations that drive an out-of-range read), the JPEG
 * standalone-marker range boundaries, and the WebP fourcc bytes that distinguish the sub-formats.
 * Every assertion fails under the targeted mutation. No tautologies.
 */
import { describe, expect, it } from 'vitest';
import { parseDimensions, sniffFormat } from './image-dimensions.js';
import { makeJpeg } from './image-fixtures.test-helper.js';

/** A JPEG with one leading standalone marker before the SOF0 frame. */
function jpegWithLeadingMarker(lead: number): Uint8Array {
  const buf = new Uint8Array(22);
  buf.set([0xff, 0xd8], 0); // SOI
  buf.set([0xff, lead], 2); // leading standalone marker under test
  buf.set([0xff, 0xc0], 4); // SOF0
  const dv = new DataView(buf.buffer);
  dv.setUint16(6, 0x0011, false);
  buf[8] = 8;
  dv.setUint16(9, 55, false); // height
  dv.setUint16(11, 77, false); // width
  return buf;
}

/** A full, valid VP8X extended WebP header with the given canvas size. */
function makeWebpVp8x(width: number, height: number): Uint8Array {
  const buf = new Uint8Array(30);
  buf.set([0x52, 0x49, 0x46, 0x46], 0);
  buf.set([0x57, 0x45, 0x42, 0x50], 8);
  buf.set([0x56, 0x50, 0x38, 0x58], 12);
  const wm1 = width - 1, hm1 = height - 1;
  buf[24] = wm1 & 0xff;
  buf[25] = (wm1 >> 8) & 0xff;
  buf[26] = (wm1 >> 16) & 0xff;
  buf[27] = hm1 & 0xff;
  buf[28] = (hm1 >> 8) & 0xff;
  buf[29] = (hm1 >> 16) & 0xff;
  return buf;
}

describe('sniffFormat rejects buffers that match no format (kills whole-condition -> true)', () => {
  it('a 12-byte all-zero buffer is not any image format', () => {
    // If the PNG/JPEG/WebP branch condition were forced `true`, this non-image buffer would be
    // misidentified. It must sniff as null for all three branches to stay honest.
    expect(sniffFormat(new Uint8Array(12))).toBeNull();
  });

  it('a JPEG-magic buffer is not mistaken for PNG or WebP, and vice-versa', () => {
    const jpegMagic = new Uint8Array(12);
    jpegMagic.set([0xff, 0xd8, 0xff], 0);
    expect(sniffFormat(jpegMagic)).toBe('image/jpeg'); // not png/webp-true

    const pngMagic = new Uint8Array(12);
    pngMagic.set([0x89, 0x50, 0x4e, 0x47, 0x0d, 0x0a, 0x1a, 0x0a], 0);
    expect(sniffFormat(pngMagic)).toBe('image/png');
  });
});

describe('JPEG reader bounds and null-arms (kills readU16BE off+N and width/height===null)', () => {
  it('returns null when the width uint16 read runs one byte past the buffer', () => {
    // makeJpeg lays out: SOI@0, SOF0@2, len@4, precision@6, height@7-8, width@9-10. The width is
    // read via readU16BE(buf, off+7) = offset 9; truncating to 10 bytes makes buf[10] OOB so the
    // width read returns null and L113's `width === null` arm fires. Kills the readU16BE bounds
    // mutant and the width-null arm.
    const truncated = makeJpeg(100, 80).slice(0, 10);
    expect(parseDimensions('image/jpeg', truncated)).toBeNull();
  });

  it('returns null when the height uint16 read runs one byte past the buffer', () => {
    // Height is read at offset 7; truncating to 8 bytes makes buf[8] OOB -> height null arm fires.
    const truncated = makeJpeg(100, 80).slice(0, 8);
    expect(parseDimensions('image/jpeg', truncated)).toBeNull();
  });

  it('returns null when the segment-length read itself is out of bounds', () => {
    // SOI + a marker that needs a length, but only the marker bytes are present.
    const buf = new Uint8Array([0xff, 0xd8, 0xff, 0xc0]); // SOF0 with no length bytes
    expect(parseDimensions('image/jpeg', buf)).toBeNull();
  });

  it('treats 0x01 (TEM) and 0xD0 (RST0, bottom of range) as standalone markers', () => {
    // Pins the `=== 0x01` arm and the lower bound of `marker >= 0xd0`. If either were neutralised
    // the parser would mis-read these as length-bearing segments and not reach the real SOF.
    expect(parseDimensions('image/jpeg', jpegWithLeadingMarker(0x01))).toEqual({
      width: 77,
      height: 55,
    });
    expect(parseDimensions('image/jpeg', jpegWithLeadingMarker(0xd0))).toEqual({
      width: 77,
      height: 55,
    });
  });

  it('rejects a JPEG whose declared segment length is exactly 2 minus one (boundary of < 2)', () => {
    const jpg = makeJpeg(10, 10);
    jpg[4] = 0x00;
    jpg[5] = 0x01; // segLen = 1, strictly below 2 -> rejected
    expect(parseDimensions('image/jpeg', jpg)).toBeNull();
  });
});

describe('WebP VP8X reader bounds and fourcc disambiguation', () => {
  it('parses a full VP8X header', () => {
    expect(parseDimensions('image/webp', makeWebpVp8x(100, 200))).toEqual({
      width: 100,
      height: 200,
    });
  });

  it('returns null when the VP8X height uint24 read runs past the buffer', () => {
    // Height occupies bytes 27,28,29; truncating to 29 makes readU24LE(buf,27) out of bounds.
    expect(parseDimensions('image/webp', makeWebpVp8x(100, 200).slice(0, 29))).toBeNull();
  });

  it('returns null when the VP8X width uint24 read runs past the buffer', () => {
    // Width occupies bytes 24,25,26; truncating to 26 makes readU24LE(buf,24) out of bounds.
    expect(parseDimensions('image/webp', makeWebpVp8x(100, 200).slice(0, 26))).toBeNull();
  });

  it('the 15th fourcc byte alone distinguishes VP8X (0x58) from VP8L (0x4c)', () => {
    // Flip only byte 15 of a VP8X header to the VP8L tag. The parser then takes the VP8L path,
    // which needs the 0x2f signature at byte 20 (absent here) -> null. Proves byte 15 is decisive.
    const x = makeWebpVp8x(100, 200);
    x[15] = 0x4c; // now "VP8L"
    expect(parseDimensions('image/webp', x)).toBeNull();
  });
});

src/rate-limit.test.ts.source:
/**
 * Tests for the sliding-window rate limiter. Boundary-exact (allow Nth / deny N+1th), refill
 * after injected time advance, per-tenant aggregate denial across shoppers, tenant independence,
 * and a property that the cap is never exceeded in any window.
 */
import { describe, expect, it } from 'vitest';
import fc from 'fast-check';
import {
  InMemoryRateLimitStore,
  RateLimiter,
  type Clock,
} from './rate-limit.js';

/** A clock whose time the test moves explicitly — no wall-clock dependency. */
class FakeClock implements Clock {
  constructor(private t = 0) {}
  now(): number {
    return this.t;
  }
  advance(ms: number): void {
    this.t += ms;
  }
}

const limits = (perShopper: number, perTenant: number) =>
  ({
    tenantId: 't1',
    shopperId: 's1',
    perShopperPerMinute: perShopper,
    perTenantPerMinute: perTenant,
  }) as const;

describe('per-shopper boundary', () => {
  it('allows exactly N then denies the N+1th in the same window', () => {
    const clock = new FakeClock();
    const rl = new RateLimiter(clock);
    for (let i = 0; i < 3; i++) {
      expect(rl.check(limits(3, 100)).allowed).toBe(true);
    }
    const denied = rl.check(limits(3, 100));
    expect(denied.allowed).toBe(false);
    expect(denied.retryAfterMs).toBeGreaterThan(0);
    expect(denied.retryAfterMs).toBeLessThanOrEqual(60_000);
  });

  it('refills after the window fully advances (injected clock)', () => {
    const clock = new FakeClock();
    const rl = new RateLimiter(clock);
    for (let i = 0; i < 2; i++) rl.check(limits(2, 100));
    expect(rl.check(limits(2, 100)).allowed).toBe(false);
    // Advance just past the 60s window so the oldest hit drops out.
    clock.advance(60_001);
    expect(rl.check(limits(2, 100)).allowed).toBe(true);
  });

  it('does not refill one millisecond before the window closes', () => {
    const clock = new FakeClock();
    const rl = new RateLimiter(clock);
    rl.check(limits(1, 100)); // hit at t=0
    clock.advance(60_000); // exactly the window: t=0 is at the cutoff, pruned only when t > cutoff
    // cutoff = now - 60000 = 0, prune keeps t > 0, so the t=0 hit is dropped -> allowed.
    expect(rl.check(limits(1, 100)).allowed).toBe(true);
  });
});

describe('per-tenant aggregate cap (threat D2)', () => {
  it('denies a second shopper once the tenant cap is hit even with per-shopper headroom', () => {
    const clock = new FakeClock();
    const rl = new RateLimiter(clock);
    // Tenant cap 2; per-shopper cap 10 (lots of headroom). Two distinct shoppers fill the tenant.
    const mk = (shopper: string) => ({
      tenantId: 't1',
      shopperId: shopper,
      perShopperPerMinute: 10,
      perTenantPerMinute: 2,
    });
    expect(rl.check(mk('sA')).allowed).toBe(true);
    expect(rl.check(mk('sB')).allowed).toBe(true);
    // sC has full per-shopper headroom but the tenant aggregate is exhausted.
    const denied = rl.check(mk('sC'));
    expect(denied.allowed).toBe(false);
    expect(denied.retryAfterMs).toBeGreaterThan(0);
  });

  it('does not record a denied request against either bucket', () => {
    const clock = new FakeClock();
    const store = new InMemoryRateLimitStore();
    const rl = new RateLimiter(clock, store);
    rl.check(limits(1, 100)); // shopper now at 1/1
    rl.check(limits(1, 100)); // denied — must not bump counts
    // Tenant bucket should hold exactly one (the allowed) hit, not two.
    expect(store.get('t:t1')).toHaveLength(1);
    expect(store.get('s:t1:s1')).toHaveLength(1);
  });
});

describe('tenant independence', () => {
  it('one tenant hitting its cap does not affect another tenant', () => {
    const clock = new FakeClock();
    const rl = new RateLimiter(clock);
    const t1 = { tenantId: 't1', shopperId: 's', perShopperPerMinute: 1, perTenantPerMinute: 1 };
    const t2 = { tenantId: 't2', shopperId: 's', perShopperPerMinute: 1, perTenantPerMinute: 1 };
    expect(rl.check(t1).allowed).toBe(true);
    expect(rl.check(t1).allowed).toBe(false);
    expect(rl.check(t2).allowed).toBe(true); // t2 is unaffected
  });
});

describe('fail-closed sizing', () => {
  it('denies all traffic when a cap is zero or negative', () => {
    const clock = new FakeClock();
    const rl = new RateLimiter(clock);
    expect(rl.check(limits(0, 100)).allowed).toBe(false);
    expect(rl.check(limits(100, 0)).allowed).toBe(false);
    expect(rl.check(limits(-5, 100)).allowed).toBe(false);
  });
});

describe('property: never allows more than the cap in any window', () => {
  it('the number of allowed requests within one window never exceeds min(caps)', () => {
    fc.assert(
      fc.property(
        fc.integer({ min: 1, max: 8 }),
        fc.integer({ min: 1, max: 8 }),
        fc.integer({ min: 1, max: 40 }),
        (perShopper, perTenant, attempts) => {
          const clock = new FakeClock();
          const rl = new RateLimiter(clock);
          let allowed = 0;
          for (let i = 0; i < attempts; i++) {
            // small advances, all well inside one 60s window
            clock.advance(10);
            if (rl.check(limits(perShopper, perTenant)).allowed) allowed++;
          }
          const cap = Math.min(perShopper, perTenant);
          return allowed <= cap;
        },
      ),
      { numRuns: 300 },
    );
  });
});

src/api-key-auth.mutation.test.ts.source:
/**
 * Mutation-hardening tests for tenant-scoped API-key verification.
 *
 * The round-trip tests cannot catch mutations to the KDF itself (both mint and verify use the
 * same code, so a mutated salt-encoding or scrypt parameter still self-consistently verifies).
 * Here we pin a FIXED known-answer vector — a literal plaintext + salt + precomputed scrypt hash
 * — so that mutating the `'hex'` salt decoding or the scrypt options object changes the derived
 * hash and breaks verification. We also exercise the non-string `typeof` guards and the
 * no-expiry spread path that the existing suite leaves untested. Boundary-exact, real teeth.
 */
import { describe, expect, it } from 'vitest';
import { createApiKey, verifyApiKey, type ApiKeyRecord } from './api-key-auth.js';

const TENANT = 'tenant-a';

/**
 * Known-answer vector: scrypt(plaintext, salt, 32, {N:2^15, r:8, p:1}) precomputed with the exact
 * parameters this module declares. If deriveHash mutates the salt encoding (`'hex' -> ''`) or the
 * options object (`{...} -> {}`, which would fall back to scrypt's default N=16384), the derived
 * hash will not equal this stored vector and verification flips to `mismatch` — killing the mutant.
 */
const FIXED = {
  plaintext: 'known-plaintext-secret',
  salt: '00112233445566778899aabbccddeeff',
  hash: '0fc7f1e64d48a2e08c8aaf308eeca13de603ba8f0e791776bba33dd23e7d7363',
} as const;

const fixedRecord = (): ApiKeyRecord => ({
  keyId: 'kid-fixed',
  tenantId: TENANT,
  scopes: [],
  salt: FIXED.salt,
  hash: FIXED.hash,
});

describe('KDF known-answer vector (kills salt-encoding and scrypt-param mutants)', () => {
  it('verifies the genuine plaintext against the precomputed scrypt hash', () => {
    expect(verifyApiKey(FIXED.plaintext, fixedRecord(), { tenantId: TENANT })).toEqual({
      ok: true,
    });
  });

  it('rejects a near-miss plaintext against the same fixed vector', () => {
    // Any other plaintext derives a different hash; proves the vector is genuinely discriminating
    // and not trivially accepted regardless of input.
    expect(verifyApiKey('known-plaintext-secres', fixedRecord(), { tenantId: TENANT })).toEqual({
      ok: false,
      reason: 'mismatch',
    });
  });
});

describe('malformed-record typeof guards (kills the false-ing of the typeof arms)', () => {
  // These use NON-STRING values that would NOT throw downstream if the guard were removed, so the
  // only thing producing `malformed` is the typeof guard itself. A numeric value would throw in
  // Buffer.from and be caught as malformed anyway (guard-redundant); an array decodes cleanly, so
  // removing the guard yields `mismatch` instead — which these exact-reason assertions catch.

  it('refuses a record whose salt is an array, not a string (reason stays malformed)', () => {
    // Array salt: if the `typeof salt !== "string"` arm were neutralised, Buffer.from(array,"hex")
    // succeeds and the derive runs to a mismatch — a different reason than malformed.
    const bad = { ...fixedRecord(), salt: [0, 1, 2, 3] as unknown as string };
    expect(verifyApiKey(FIXED.plaintext, bad, { tenantId: TENANT })).toEqual({
      ok: false,
      reason: 'malformed',
    });
  });

  it('refuses a record whose hash is an array, not a string (reason stays malformed)', () => {
    const bad = { ...fixedRecord(), hash: [1, 2, 3] as unknown as string };
    expect(verifyApiKey(FIXED.plaintext, bad, { tenantId: TENANT })).toEqual({
      ok: false,
      reason: 'malformed',
    });
  });

  it('refuses a Buffer plaintext even when it would derive the genuine hash', () => {
    // Buffer.from("known-plaintext-secret") is a valid scrypt password; if the plaintext typeof
    // guard were removed it would derive the stored hash and WRONGLY return ok:true. The guard
    // must refuse it as malformed because plaintext is not a string.
    const bufPlaintext = Buffer.from(FIXED.plaintext, 'utf8') as unknown as string;
    expect(verifyApiKey(bufPlaintext, fixedRecord(), { tenantId: TENANT })).toEqual({
      ok: false,
      reason: 'malformed',
    });
  });
});

describe('createApiKey expiry-spread path (kills the L118 conditional)', () => {
  it('omits expiresAt entirely when none is supplied', () => {
    const { record } = createApiKey({ tenantId: TENANT, scopes: [] });
    // If the spread condition were forced true, the record would carry `expiresAt: undefined`.
    expect('expiresAt' in record).toBe(false);
    expect(Object.prototype.hasOwnProperty.call(record, 'expiresAt')).toBe(false);
  });

  it('includes expiresAt verbatim when supplied', () => {
    const exp = '2099-01-01T00:00:00.000Z';
    const { record } = createApiKey({ tenantId: TENANT, scopes: [], expiresAt: exp });
    expect(record.expiresAt).toBe(exp);
  });
});

